import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import type { Order } from '../../src/models/order.js';
import type { User } from '../../src/models/user.js';

function makeUser(overrides: Partial<User> = {}): User {
  return {
    id: 'user-1',
    name: 'Alice',
    email: 'alice@example.com',
    role: 'member',
    createdAt: new Date('2025-01-01'),
    updatedAt: new Date('2025-01-01'),
    ...overrides,
  };
}

function makeOrder(overrides: Partial<Order> = {}): Order {
  return {
    id: 'order-1',
    userId: 'user-1',
    items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
    total: 20,
    status: 'pending',
    createdAt: new Date('2025-03-15T10:30:00Z'),
    updatedAt: new Date('2025-03-15T10:30:00Z'),
    ...overrides,
  };
}

describe('AnalyticsService', () => {
  let db: Database;
  let orderRepo: OrderRepository;
  let userRepo: UserRepository;
  let service: AnalyticsService;

  beforeEach(() => {
    db = new Database();
    orderRepo = new OrderRepository(db);
    userRepo = new UserRepository(db);
    service = new AnalyticsService(orderRepo, userRepo);
  });

  // ── getOrderMetrics ──────────────────────────────────────────────

  describe('getOrderMetrics', () => {
    it('should return zeros when there are no orders', () => {
      const metrics = service.getOrderMetrics();

      expect(metrics.totalOrders).toBe(0);
      expect(metrics.totalRevenue).toBe(0);
      expect(metrics.averageOrderValue).toBe(0);
      expect(metrics.ordersByStatus).toEqual({
        pending: 0,
        confirmed: 0,
        shipped: 0,
        delivered: 0,
        cancelled: 0,
      });
    });

    it('should compute metrics for a single order', () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 50, status: 'pending' }));

      const metrics = service.getOrderMetrics();

      expect(metrics.totalOrders).toBe(1);
      expect(metrics.totalRevenue).toBe(50);
      expect(metrics.averageOrderValue).toBe(50);
      expect(metrics.ordersByStatus.pending).toBe(1);
    });

    it('should compute metrics for multiple orders with different statuses', () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 100, status: 'pending' }));
      orderRepo.save(makeOrder({ id: 'o2', total: 200, status: 'confirmed' }));
      orderRepo.save(makeOrder({ id: 'o3', total: 300, status: 'delivered' }));

      const metrics = service.getOrderMetrics();

      expect(metrics.totalOrders).toBe(3);
      expect(metrics.totalRevenue).toBe(600);
      expect(metrics.averageOrderValue).toBe(200);
      expect(metrics.ordersByStatus.pending).toBe(1);
      expect(metrics.ordersByStatus.confirmed).toBe(1);
      expect(metrics.ordersByStatus.delivered).toBe(1);
      expect(metrics.ordersByStatus.shipped).toBe(0);
      expect(metrics.ordersByStatus.cancelled).toBe(0);
    });

    it('should round revenue and average to two decimal places', () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 10.333 }));
      orderRepo.save(makeOrder({ id: 'o2', total: 10.333 }));
      orderRepo.save(makeOrder({ id: 'o3', total: 10.333 }));

      const metrics = service.getOrderMetrics();

      expect(metrics.totalRevenue).toBe(31);
      expect(metrics.averageOrderValue).toBe(10.33);
    });
  });

  // ── getUserMetrics ───────────────────────────────────────────────

  describe('getUserMetrics', () => {
    it('should return zero when there are no users', () => {
      const metrics = service.getUserMetrics();

      expect(metrics.totalUsers).toBe(0);
      expect(metrics.usersByRole).toEqual({});
    });

    it('should count users by role', () => {
      userRepo.save(makeUser({ id: 'u1', email: 'a@a.com', role: 'admin' }));
      userRepo.save(makeUser({ id: 'u2', email: 'b@b.com', role: 'member' }));
      userRepo.save(makeUser({ id: 'u3', email: 'c@c.com', role: 'member' }));
      userRepo.save(makeUser({ id: 'u4', email: 'd@d.com', role: 'viewer' }));

      const metrics = service.getUserMetrics();

      expect(metrics.totalUsers).toBe(4);
      expect(metrics.usersByRole).toEqual({
        admin: 1,
        member: 2,
        viewer: 1,
      });
    });

    it('should handle a single user', () => {
      userRepo.save(makeUser({ id: 'u1', role: 'admin' }));

      const metrics = service.getUserMetrics();

      expect(metrics.totalUsers).toBe(1);
      expect(metrics.usersByRole).toEqual({ admin: 1 });
    });
  });

  // ── getTopProducts ───────────────────────────────────────────────

  describe('getTopProducts', () => {
    it('should return empty array when there are no orders', () => {
      const products = service.getTopProducts();
      expect(products).toEqual([]);
    });

    it('should aggregate product revenue across orders', () => {
      orderRepo.save(
        makeOrder({
          id: 'o1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          ],
        }),
      );
      orderRepo.save(
        makeOrder({
          id: 'o2',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 3, unitPrice: 10 },
          ],
        }),
      );

      const products = service.getTopProducts();

      expect(products).toHaveLength(1);
      expect(products[0]!.productId).toBe('p1');
      expect(products[0]!.totalQuantity).toBe(5);
      expect(products[0]!.totalRevenue).toBe(50);
    });

    it('should sort products by revenue descending', () => {
      orderRepo.save(
        makeOrder({
          id: 'o1',
          items: [
            { productId: 'p1', name: 'Cheap', quantity: 10, unitPrice: 1 },
            { productId: 'p2', name: 'Expensive', quantity: 1, unitPrice: 100 },
          ],
        }),
      );

      const products = service.getTopProducts();

      expect(products[0]!.productId).toBe('p2');
      expect(products[0]!.totalRevenue).toBe(100);
      expect(products[1]!.productId).toBe('p1');
      expect(products[1]!.totalRevenue).toBe(10);
    });

    it('should respect the limit parameter', () => {
      orderRepo.save(
        makeOrder({
          id: 'o1',
          items: [
            { productId: 'p1', name: 'A', quantity: 1, unitPrice: 30 },
            { productId: 'p2', name: 'B', quantity: 1, unitPrice: 20 },
            { productId: 'p3', name: 'C', quantity: 1, unitPrice: 10 },
          ],
        }),
      );

      const products = service.getTopProducts(2);

      expect(products).toHaveLength(2);
      expect(products[0]!.productId).toBe('p1');
      expect(products[1]!.productId).toBe('p2');
    });

    it('should round revenue to two decimal places', () => {
      orderRepo.save(
        makeOrder({
          id: 'o1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 3, unitPrice: 3.333 },
          ],
        }),
      );

      const products = service.getTopProducts();

      expect(products[0]!.totalRevenue).toBe(10);
    });
  });

  // ── aggregateTimeSeries ──────────────────────────────────────────

  describe('aggregateTimeSeries', () => {
    it('should return empty array when there are no orders', () => {
      const result = service.aggregateTimeSeries('day');
      expect(result).toEqual([]);
    });

    it('should group orders by day', () => {
      orderRepo.save(
        makeOrder({
          id: 'o1',
          total: 10,
          createdAt: new Date('2025-03-15T08:00:00Z'),
        }),
      );
      orderRepo.save(
        makeOrder({
          id: 'o2',
          total: 20,
          createdAt: new Date('2025-03-15T16:00:00Z'),
        }),
      );
      orderRepo.save(
        makeOrder({
          id: 'o3',
          total: 30,
          createdAt: new Date('2025-03-16T10:00:00Z'),
        }),
      );

      const result = service.aggregateTimeSeries('day');

      expect(result).toHaveLength(2);
      // First bucket: two orders from March 15
      expect(result[0]!.count).toBe(2);
      expect(result[0]!.revenue).toBe(30);
      // Second bucket: one order from March 16
      expect(result[1]!.count).toBe(1);
      expect(result[1]!.revenue).toBe(30);
    });

    it('should group orders by hour', () => {
      orderRepo.save(
        makeOrder({
          id: 'o1',
          total: 10,
          createdAt: new Date('2025-03-15T10:15:00Z'),
        }),
      );
      orderRepo.save(
        makeOrder({
          id: 'o2',
          total: 20,
          createdAt: new Date('2025-03-15T10:45:00Z'),
        }),
      );
      orderRepo.save(
        makeOrder({
          id: 'o3',
          total: 30,
          createdAt: new Date('2025-03-15T11:05:00Z'),
        }),
      );

      const result = service.aggregateTimeSeries('hour');

      expect(result).toHaveLength(2);
      expect(result[0]!.count).toBe(2);
      expect(result[0]!.revenue).toBe(30);
      expect(result[1]!.count).toBe(1);
      expect(result[1]!.revenue).toBe(30);
    });

    it('should group orders by month', () => {
      orderRepo.save(
        makeOrder({
          id: 'o1',
          total: 100,
          createdAt: new Date('2025-03-05T10:00:00Z'),
        }),
      );
      orderRepo.save(
        makeOrder({
          id: 'o2',
          total: 200,
          createdAt: new Date('2025-03-20T10:00:00Z'),
        }),
      );
      orderRepo.save(
        makeOrder({
          id: 'o3',
          total: 300,
          createdAt: new Date('2025-04-10T10:00:00Z'),
        }),
      );

      const result = service.aggregateTimeSeries('month');

      expect(result).toHaveLength(2);
      expect(result[0]!.count).toBe(2);
      expect(result[0]!.revenue).toBe(300);
      expect(result[1]!.count).toBe(1);
      expect(result[1]!.revenue).toBe(300);
    });

    it('should filter by startDate', () => {
      orderRepo.save(
        makeOrder({
          id: 'o1',
          total: 10,
          createdAt: new Date('2025-03-01T10:00:00Z'),
        }),
      );
      orderRepo.save(
        makeOrder({
          id: 'o2',
          total: 20,
          createdAt: new Date('2025-03-15T10:00:00Z'),
        }),
      );

      const result = service.aggregateTimeSeries(
        'day',
        new Date('2025-03-10T00:00:00Z'),
      );

      expect(result).toHaveLength(1);
      expect(result[0]!.revenue).toBe(20);
    });

    it('should filter by endDate', () => {
      orderRepo.save(
        makeOrder({
          id: 'o1',
          total: 10,
          createdAt: new Date('2025-03-01T10:00:00Z'),
        }),
      );
      orderRepo.save(
        makeOrder({
          id: 'o2',
          total: 20,
          createdAt: new Date('2025-03-15T10:00:00Z'),
        }),
      );

      const result = service.aggregateTimeSeries(
        'day',
        undefined,
        new Date('2025-03-10T00:00:00Z'),
      );

      expect(result).toHaveLength(1);
      expect(result[0]!.revenue).toBe(10);
    });

    it('should filter by both startDate and endDate', () => {
      orderRepo.save(
        makeOrder({
          id: 'o1',
          total: 10,
          createdAt: new Date('2025-03-01T10:00:00Z'),
        }),
      );
      orderRepo.save(
        makeOrder({
          id: 'o2',
          total: 20,
          createdAt: new Date('2025-03-15T10:00:00Z'),
        }),
      );
      orderRepo.save(
        makeOrder({
          id: 'o3',
          total: 30,
          createdAt: new Date('2025-03-30T10:00:00Z'),
        }),
      );

      const result = service.aggregateTimeSeries(
        'day',
        new Date('2025-03-10T00:00:00Z'),
        new Date('2025-03-20T00:00:00Z'),
      );

      expect(result).toHaveLength(1);
      expect(result[0]!.revenue).toBe(20);
    });

    it('should sort results chronologically', () => {
      // Insert out of order
      orderRepo.save(
        makeOrder({
          id: 'o2',
          total: 20,
          createdAt: new Date('2025-03-20T10:00:00Z'),
        }),
      );
      orderRepo.save(
        makeOrder({
          id: 'o1',
          total: 10,
          createdAt: new Date('2025-03-10T10:00:00Z'),
        }),
      );

      const result = service.aggregateTimeSeries('day');

      expect(result).toHaveLength(2);
      expect(result[0]!.revenue).toBe(10);
      expect(result[1]!.revenue).toBe(20);
    });

    it('should handle a single data point', () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 42 }));

      const result = service.aggregateTimeSeries('day');

      expect(result).toHaveLength(1);
      expect(result[0]!.count).toBe(1);
      expect(result[0]!.revenue).toBe(42);
    });
  });

  // ── getOrderMetricsForPeriod ─────────────────────────────────────

  describe('getOrderMetricsForPeriod', () => {
    it('should return metrics only for orders within the period', () => {
      orderRepo.save(
        makeOrder({
          id: 'o1',
          total: 100,
          status: 'pending',
          createdAt: new Date('2025-03-01T10:00:00Z'),
        }),
      );
      orderRepo.save(
        makeOrder({
          id: 'o2',
          total: 200,
          status: 'confirmed',
          createdAt: new Date('2025-03-15T10:00:00Z'),
        }),
      );
      orderRepo.save(
        makeOrder({
          id: 'o3',
          total: 300,
          status: 'shipped',
          createdAt: new Date('2025-03-30T10:00:00Z'),
        }),
      );

      const metrics = service.getOrderMetricsForPeriod(
        new Date('2025-03-10T00:00:00Z'),
        new Date('2025-03-20T00:00:00Z'),
      );

      expect(metrics.totalOrders).toBe(1);
      expect(metrics.totalRevenue).toBe(200);
      expect(metrics.averageOrderValue).toBe(200);
      expect(metrics.ordersByStatus.confirmed).toBe(1);
    });

    it('should return zeros when no orders fall in the period', () => {
      orderRepo.save(
        makeOrder({
          id: 'o1',
          total: 100,
          createdAt: new Date('2025-01-01T10:00:00Z'),
        }),
      );

      const metrics = service.getOrderMetricsForPeriod(
        new Date('2025-06-01T00:00:00Z'),
        new Date('2025-06-30T00:00:00Z'),
      );

      expect(metrics.totalOrders).toBe(0);
      expect(metrics.totalRevenue).toBe(0);
      expect(metrics.averageOrderValue).toBe(0);
    });

    it('should include orders on exact boundary dates', () => {
      const start = new Date('2025-03-15T00:00:00Z');
      const end = new Date('2025-03-15T23:59:59Z');

      orderRepo.save(
        makeOrder({ id: 'o1', total: 50, createdAt: start }),
      );
      orderRepo.save(
        makeOrder({ id: 'o2', total: 75, createdAt: end }),
      );

      const metrics = service.getOrderMetricsForPeriod(start, end);

      expect(metrics.totalOrders).toBe(2);
      expect(metrics.totalRevenue).toBe(125);
    });
  });

  // ── getDashboardData ─────────────────────────────────────────────

  describe('getDashboardData', () => {
    it('should compose all analytics sources', () => {
      userRepo.save(makeUser({ id: 'u1', email: 'a@a.com', role: 'admin' }));
      orderRepo.save(
        makeOrder({
          id: 'o1',
          total: 100,
          status: 'delivered',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 100 },
          ],
        }),
      );

      const dashboard = service.getDashboardData();

      expect(dashboard.orderMetrics.totalOrders).toBe(1);
      expect(dashboard.orderMetrics.totalRevenue).toBe(100);
      expect(dashboard.userMetrics.totalUsers).toBe(1);
      expect(dashboard.timeSeries).toHaveLength(1);
      expect(dashboard.topProducts).toHaveLength(1);
      expect(dashboard.generatedAt).toBeInstanceOf(Date);
    });

    it('should return empty dashboard when no data exists', () => {
      const dashboard = service.getDashboardData();

      expect(dashboard.orderMetrics.totalOrders).toBe(0);
      expect(dashboard.userMetrics.totalUsers).toBe(0);
      expect(dashboard.timeSeries).toEqual([]);
      expect(dashboard.topProducts).toEqual([]);
      expect(dashboard.generatedAt).toBeInstanceOf(Date);
    });

    it('should pass through granularity and date filters', () => {
      orderRepo.save(
        makeOrder({
          id: 'o1',
          total: 10,
          createdAt: new Date('2025-03-01T10:00:00Z'),
        }),
      );
      orderRepo.save(
        makeOrder({
          id: 'o2',
          total: 20,
          createdAt: new Date('2025-03-15T10:00:00Z'),
        }),
      );

      const dashboard = service.getDashboardData(
        'month',
        new Date('2025-03-10T00:00:00Z'),
      );

      // Time series should only have the filtered order
      expect(dashboard.timeSeries).toHaveLength(1);
      expect(dashboard.timeSeries[0]!.revenue).toBe(20);
      // Order metrics are unfiltered (all orders)
      expect(dashboard.orderMetrics.totalOrders).toBe(2);
    });

    it('should respect topProductsLimit', () => {
      orderRepo.save(
        makeOrder({
          id: 'o1',
          items: [
            { productId: 'p1', name: 'A', quantity: 1, unitPrice: 30 },
            { productId: 'p2', name: 'B', quantity: 1, unitPrice: 20 },
            { productId: 'p3', name: 'C', quantity: 1, unitPrice: 10 },
          ],
        }),
      );

      const dashboard = service.getDashboardData('day', undefined, undefined, 1);

      expect(dashboard.topProducts).toHaveLength(1);
      expect(dashboard.topProducts[0]!.productId).toBe('p1');
    });
  });

  // ── Large dataset ────────────────────────────────────────────────

  describe('large dataset handling', () => {
    it('should handle many orders without error', () => {
      for (let i = 0; i < 500; i++) {
        orderRepo.save(
          makeOrder({
            id: `order-${i}`,
            total: i + 1,
            status: i % 2 === 0 ? 'pending' : 'delivered',
            createdAt: new Date(`2025-01-${String((i % 28) + 1).padStart(2, '0')}T10:00:00Z`),
            items: [
              {
                productId: `p${i % 5}`,
                name: `Product ${i % 5}`,
                quantity: 1,
                unitPrice: i + 1,
              },
            ],
          }),
        );
      }

      const metrics = service.getOrderMetrics();
      expect(metrics.totalOrders).toBe(500);
      expect(metrics.totalRevenue).toBe(125250); // sum of 1..500

      const timeSeries = service.aggregateTimeSeries('day');
      expect(timeSeries.length).toBeGreaterThan(0);
      expect(timeSeries.length).toBeLessThanOrEqual(28);

      const topProducts = service.getTopProducts(3);
      expect(topProducts).toHaveLength(3);

      const dashboard = service.getDashboardData();
      expect(dashboard.orderMetrics.totalOrders).toBe(500);
    });
  });
});

